mapper.select:
WITH RECURSIVE FilePath AS ( SELECT FM_ID, FM_UP_FILE_ID, FM_FILE_NAME, 1 AS depth FROM FILE_MANAGE WHERE FM_ID = #{FM_ID}
UNION ALL
SELECT f.FM_ID, f.FM_UP_FILE_ID, f.FM_FILE_NAME, fp.depth + 1 FROM FILE_MANAGE f INNER JOIN FilePath fp ON f.FM_ID = fp.FM_UP_FILE_ID ) SELECT GROUP_CONCAT(FM_FILE_NAME ORDER BY depth DESC SEPARATOR '/') AS FULL_PATH FROM FilePath;
